#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/stat.h>

int main() {
 // Using standard library
 FILE *fp;

 // Create and write
 fp = fopen("test.txt", "w");
 if (fp == NULL) {
 perror("fopen");
 return 1;
 }
 fprintf(fp, "Hello, File Systems!\n");
 fclose(fp);

 // Read
 fp = fopen("test.txt", "r");
 char buffer[100];
 fgets(buffer, 100, fp);
 printf("Read: %s", buffer);
 fclose(fp);

 // Using system calls
 int fd;

 // Open with flags
 fd = open("test2.txt", O_CREAT | O_WRONLY, 0644);
 write(fd, "System call write\n", 18);
 close(fd);

 // File info
 struct stat st;
 stat("test.txt", &st);
 printf("Size: %lld bytes\n", (long long)st.st_size);
 printf("Inode: %llu\n", (unsigned long long)st.st_ino);

 // Delete
 remove("test.txt");
 unlink("test2.txt");

 return 0;
}

import java.io.*;
import java.nio.file.*;
import java.nio.file.attribute.*;

public class FileOperations {
 public static void main(String[] args) throws IOException {
 Path path = Paths.get("test.txt");

 // Create and write
 Files.write(path, "Hello, File Systems!\n".getBytes());
 System.out.println("File created");

 // Read
 String content = Files.readString(path);
 System.out.println("Content: " + content);

 // File attributes
 BasicFileAttributes attrs = Files.readAttributes(
 path, BasicFileAttributes.class);

 System.out.println("\nFile Attributes:");
 System.out.println("Size: " + attrs.size() + " bytes");
 System.out.println("Created: " + attrs.creationTime());
 System.out.println("Modified: " + attrs.lastModifiedTime());
 System.out.println("Is Directory: " + attrs.isDirectory());

 // Random access
 try (RandomAccessFile raf = new RandomAccessFile("test.txt", "rw")) {
 raf.seek(7); // Move to position 7
 byte[] buffer = new byte[10];
 raf.read(buffer);
 System.out.println("\nFrom position 7: " + new String(buffer));
 }

 // Delete
 Files.delete(path);
 System.out.println("\nFile deleted");
 }
}
